import { getInterviewQuestions } from '@/lib/strapi';

export default async function PracticePage() {
    const questions = await getInterviewQuestions();

    // Group questions by category
    const groupedQuestions: Record<string, any[]> = {};
    if (questions) {
        questions.forEach((q: any) => {
            const category = q.category || 'Other';
            if (!groupedQuestions[category]) {
                groupedQuestions[category] = [];
            }
            groupedQuestions[category].push(q);
        });
    }

    return (
        <div className="container mx-auto px-4 py-8">
            <h1 className="text-4xl font-bold mb-8 text-center text-gray-800">Interview Practice</h1>

            {Object.keys(groupedQuestions).length === 0 ? (
                <p className="text-center text-gray-500">No interview questions found. Please add some in the CMS.</p>
            ) : (
                Object.entries(groupedQuestions).map(([category, items]) => (
                    <div key={category} className="mb-12">
                        <h2 className="text-2xl font-bold mb-4 text-gray-700 border-b pb-2">{category} Questions</h2>
                        <div className="grid gap-4">
                            {items.map((q: any) => (
                                <div key={q.id} className="bg-white p-6 rounded-lg shadow-sm border border-gray-100 hover:border-blue-200 transition-colors">
                                    <div className="flex justify-between items-start mb-2">
                                        <h3 className="text-lg font-medium text-gray-900">{q.question}</h3>
                                        <span className={`px-2 py-1 rounded text-xs font-semibold 
                                    ${q.difficulty === 'Easy' ? 'bg-green-100 text-green-800' :
                                                q.difficulty === 'Medium' ? 'bg-yellow-100 text-yellow-800' :
                                                    'bg-red-100 text-red-800'}`}>
                                            {q.difficulty}
                                        </span>
                                    </div>
                                    {q.expectedAnswer && (
                                        <details className="mt-4">
                                            <summary className="cursor-pointer text-blue-600 text-sm font-medium hover:text-blue-800">Show Expected Key Points</summary>
                                            <div className="mt-2 p-4 bg-gray-50 rounded text-gray-700 text-sm prose">
                                                {/* Simple rendering for now, rich text handling can be added later */}
                                                {JSON.stringify(q.expectedAnswer).substring(0, 100)}...
                                            </div>
                                        </details>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                ))
            )}
        </div>
    );
}
